alias={}
for g in swg:
    k=g.get('same_work_id') or ('canon:%s'%g.get('canonical_index'))
    for m in g.get('member_evidence_ids') or []:
        alias.setdefault(str(m),k)
def ntitle(t):
    t=(t or '').lower(); t=re.sub(r'[^a-z0-9]+','',t); return t
# title fold >=25 alnum
tg={}
for e in ev:
    k=ntitle(e.get('title'))
    if len(k)>=25: tg.setdefault('title:'+k,[]).append(e['evidence_id'])
for k,mem in tg.items():
    if len(mem)<2: continue
    stamped={alias[m] for m in mem if m in alias}
    key=list(stamped)[0] if len(stamped)==1 else k
    for m in mem: alias.setdefault(m,key)
works=set(alias.get(e['evidence_id'], e['evidence_id']) for e in ev)
